import Header from '../components/Header'

function AppContainer() {
    const {
        canvasRef,
        objects,
        newObject,
        startDragging,
        dragging,
        stopDragging,
    } = useCanvasObjects();

    return (
        <div className="app-container">
            <Header></Header>

            <div className="main">
                <aside className="sidebar">
                    <button onClick={newObject}>Добавить объект</button>
                </aside>

                <div
                    className="canvas-container"
                    ref={canvasRef}
                    onMouseMove={dragging}
                    onMouseUp={stopDragging}
                    style={{ position: 'relative' }}
                >
                    {objects.map((obj) => (
                        <div
                            key={obj.id}
                            className="obj"
                            onMouseDown={(e) => startDragging(obj.id, e)}
                            style={{
                                position: 'absolute',
                                left: obj.left,
                                top: obj.top,
                            }}
                        />
                    ))}
                </div>
            </div>
        </div>
    );
}

export default AppContainer;
